import React, { useState, useEffect, useRef } from 'react';
import {
  View,
  Text,
  StyleSheet,
  SafeAreaView,
  TouchableOpacity,
  Image,
  ScrollView,
  TextInput,
  Platform
} from 'react-native';
import { Ionicons } from '@expo/vector-icons';
import { useAuth } from '../utils/AuthContext';
import { typography } from '../styles/typography';
import Dropdown from '../components/Dropdown';
import { getFrequentLocations, addFrequentLocation } from '../utils/storage';
import * as Location from 'expo-location';

const mockOutfit = {
  top: require('../assets/mock/top.png'),
  outerwear: require('../assets/mock/outerwear.png'),
  bottoms: require('../assets/mock/bottoms.png'),
  shoes: require('../assets/mock/shoes.png'),
  accessory: require('../assets/mock/accessory.png'),
};

const MOCK_LOCATIONS = [
  { name: 'New York, NY', country: 'US' },
  { name: 'Washington, DC', country: 'US' },
];

const HomeScreen: React.FC = () => {
  const { user } = useAuth();
  const [editingLocation, setEditingLocation] = useState(false);
  const [locationInput, setLocationInput] = useState(user?.location || '');
  const [frequentLocations, setFrequentLocations] = useState<string[]>([]);
  const [dropdownVisible, setDropdownVisible] = useState(false);
  const locationBarRef = useRef<View>(null);

  useEffect(() => {
    getFrequentLocations().then(setFrequentLocations);
  }, []);

  // Merge frequent locations and mock locations, frequent first, no duplicates
  const filteredLocations = [
    ...frequentLocations
      .filter(fl => fl.toLowerCase().includes(locationInput.toLowerCase()))
      .map(l => ({ name: l, country: '' })),
    ...MOCK_LOCATIONS.filter(
      loc =>
        loc.name.toLowerCase().includes(locationInput.toLowerCase()) &&
        !frequentLocations.includes(loc.name)
    ),
  ];

  const handleLocationSelect = async (loc: { name: string }) => {
    setLocationInput(loc.name);
    setEditingLocation(false);
    setDropdownVisible(false);
    await addFrequentLocation(loc.name);
    setFrequentLocations(await getFrequentLocations());
  };

  // Pin button: get device location and reverse geocode
  const handlePinPress = async () => {
    try {
      let { status } = await Location.requestForegroundPermissionsAsync();
      if (status !== 'granted') {
        alert('Permission to access location was denied');
        return;
      }
      let loc = await Location.getCurrentPositionAsync({});
      let geocode = await Location.reverseGeocodeAsync({
        latitude: loc.coords.latitude,
        longitude: loc.coords.longitude,
      });
      if (geocode && geocode.length > 0) {
        const { city, region, country } = geocode[0];
        const locationName = city || region || country || '';
        if (locationName) {
          setLocationInput(locationName);
          await addFrequentLocation(locationName);
          setFrequentLocations(await getFrequentLocations());
        }
      }
    } catch (e) {
      alert('Could not get current location');
    }
  };

  return (
    <SafeAreaView style={styles.safeArea}>
      <ScrollView contentContainerStyle={styles.container} showsVerticalScrollIndicator={false} keyboardShouldPersistTaps="handled">
        <View style={styles.greetingRow}>
          <View>
            <Text style={typography.label}>GOOD MORNING,</Text>
            <Text style={StyleSheet.flatten([typography.heading, styles.name])}>{user?.name || ''}</Text>
          </View>
          <TouchableOpacity style={styles.bellButton}>
            <Ionicons name="notifications-outline" size={28} color="#000" />
          </TouchableOpacity>
        </View>
        <View style={styles.locationRow}>
          <View
            ref={locationBarRef}
            style={[styles.locationInput, editingLocation && styles.locationInputActive, { position: 'relative', zIndex: 20 }]}
          >
            <TextInput
              style={[typography.body, styles.locationTextInput]}
              value={locationInput}
              onChangeText={text => {
                setLocationInput(text);
                setEditingLocation(true);
                setDropdownVisible(true);
              }}
              placeholder="Search for a location"
              placeholderTextColor="#757575"
              editable={true}
              onFocus={() => {
                setEditingLocation(true);
                setDropdownVisible(true);
              }}
              onBlur={() => {
                setEditingLocation(false);
                // Do not close dropdown on blur
              }}
              onSubmitEditing={() => {
                // If the input matches a valid location, close dropdown
                const match = filteredLocations.find(loc => loc.name.toLowerCase() === locationInput.toLowerCase());
                if (match) {
                  setDropdownVisible(false);
                  setEditingLocation(false);
                }
              }}
              autoCorrect={false}
              autoCapitalize="words"
            />
            <TouchableOpacity
              onPress={handlePinPress}
              style={{ marginLeft: 4 }}
            >
              <Ionicons name={Platform.OS === 'ios' ? 'location' : 'location-outline'} size={18} color="#757575" />
            </TouchableOpacity>
            <Dropdown
              visible={dropdownVisible && editingLocation && filteredLocations.length > 0}
              options={filteredLocations}
              onSelect={handleLocationSelect}
              renderOption={item => (
                <Text style={typography.body}>{item.name}</Text>
              )}
              onRequestClose={() => setDropdownVisible(false)}
              style={{ position: 'absolute', top: 44, left: 0, right: 0 }}
            />
          </View>
          <TouchableOpacity style={styles.todayButton}>
            <Ionicons name="calendar-outline" size={16} color="#000" />
            <Text style={typography.body}>Today</Text>
          </TouchableOpacity>
        </View>
        <View style={styles.datesRow}>
          {['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'].map((day, i) => (
            <View
              key={day}
              style={[styles.dateCell, i === 3 && styles.dateCellActive]}
            >
              <Text style={StyleSheet.flatten([typography.caption, i === 3 && styles.dateDayActive])}>{day}</Text>
              <Text style={StyleSheet.flatten([typography.body, i === 3 && styles.dateNumActive])}>{7 + i}</Text>
            </View>
          ))}
        </View>
        <View style={styles.outfitHeaderRow}>
          <Text style={StyleSheet.flatten([typography.subheading, styles.outfitHeader])}>
            TODAY'S <Text style={StyleSheet.flatten([typography.heading, styles.outfitHeaderItalic])}>Outfit</Text>
          </Text>
          <TouchableOpacity>
            <Text style={StyleSheet.flatten([typography.caption, styles.switchWeather])}>SWITCH TO <Text style={StyleSheet.flatten([typography.label, styles.weatherMode])}>weather mode</Text></Text>
          </TouchableOpacity>
        </View>
        <View style={styles.actionRow}>
          <TouchableOpacity style={styles.actionButton}><Text style={typography.button}>EDIT</Text></TouchableOpacity>
